customScripts.tabbed_tabs:
(function(root,ctx){
  function toArray(list){return Array.prototype.slice.call(list||[]);}
  function init(scope){
    if(!scope||scope.__mfTabbedTabsReady)return;
    scope.__mfTabbedTabsReady=true;
    var steps=toArray(scope.querySelectorAll('[data-mf-native-step]'));
    var pages=toArray(scope.querySelectorAll('[data-mf-native-page]'));
    var tabbar=scope.querySelector('.mfp-tabbar');
    var tabList=scope.querySelector('.mfp-tab-list');
    var back=scope.querySelector('[data-mf-native-back]');
    var next=scope.querySelector('[data-mf-native-next]');
    var submit=scope.querySelector('[data-mf-native-submit]');
    var progress=scope.querySelector('.mfp-completion,.mfp-progress-caption');
    var reviewError=scope.querySelector('.mfp-review-error');
    var total=Math.max(steps.length,pages.length);
    var requiredTotal=Math.max(0,total-1);
    var attempted=[];
    if(!total)return;
    function button(btn,show){
      if(!btn)return;
      btn.hidden=!show;
      btn.style.display=show?'inline-flex':'none';
      btn.setAttribute('aria-hidden',show?'false':'true');
    }
    function setReviewError(show){
      if(!reviewError)return;
      reviewError.hidden=!show;
      reviewError.style.display=show?'flex':'none';
    }
    function current(){
      var raw=scope.getAttribute('data-mf-current-step');
      var idx=parseInt(raw||'0',10);
      return isNaN(idx)?0:idx;
    }
    function controlValue(control){
      if(!control)return'';
      if(control.tagName==='SELECT')return String(control.value||'').trim();
      return String(control.value||'').trim();
    }
    function relevantControls(group){
      return toArray(group.querySelectorAll('input,select,textarea')).filter(function(control){
        var type=String(control.type||'').toLowerCase();
        return !control.disabled&&type!=='hidden'&&type!=='button'&&type!=='submit'&&type!=='reset';
      });
    }
    function groupRequired(group,controls){
      if(group.querySelector('.mf-required'))return true;
      return controls.some(function(control){return control.required||control.getAttribute('aria-required')==='true';});
    }
    function inspectGroup(group){
      var controls=relevantControls(group);
      if(!controls.length)return{required:false,valid:true,message:''};
      var required=groupRequired(group,controls);
      if(!required)return{required:false,valid:true,message:''};
      var choiceControls=controls.filter(function(control){var type=String(control.type||'').toLowerCase();return type==='radio'||type==='checkbox';});
      if(choiceControls.length){
        var ok=choiceControls.some(function(control){return control.checked;});
        return{required:true,valid:ok,message:'Please choose an option.'};
      }
      var first=controls[0];
      var value=controlValue(first);
      if(!value)return{required:true,valid:false,message:'Complete this required field.'};
      if(String(first.type||'').toLowerCase()==='email'){
        var emailOk=/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
        return{required:true,valid:emailOk,message:'Enter a valid email address.'};
      }
      return{required:true,valid:true,message:''};
    }
    function pageFor(idx){return pages[idx]||null;}
    function pageGroups(page){return page?toArray(page.querySelectorAll('.mf-field-group')):[];}
    function computePageValid(idx){
      if(idx>=requiredTotal)return allRequiredComplete();
      var page=pageFor(idx);
      if(!page)return true;
      return pageGroups(page).every(function(group){return inspectGroup(group).valid;});
    }
    function allRequiredComplete(){
      for(var i=0;i<requiredTotal;i++){
        var page=pageFor(i);
        if(!page)continue;
        var valid=pageGroups(page).every(function(group){return inspectGroup(group).valid;});
        if(!valid)return false;
      }
      return true;
    }
    function completeCount(){
      var count=0;
      for(var i=0;i<requiredTotal;i++)if(computePageValid(i))count++;
      return count;
    }
    function ensureError(group,message){
      var err=group.querySelector('.mfp-inline-error');
      if(!err){
        err=document.createElement('div');
        err.className='mfp-inline-error';
        group.appendChild(err);
      }
      err.textContent=message||'Complete this required field.';
    }
    function validatePage(idx,show){
      if(idx>=requiredTotal){
        var all=allRequiredComplete();
        return all;
      }
      var page=pageFor(idx);
      if(!page)return true;
      var valid=true;
      pageGroups(page).forEach(function(group){
        var result=inspectGroup(group);
        var bad=result.required&&!result.valid;
        valid=valid&&!bad;
        group.classList.toggle('mfp-field-error-state',!!show&&bad);
        if(bad)ensureError(group,result.message);
      });
      page.classList.toggle('mfp-show-errors',!!show&&!valid);
      return valid;
    }
    function clearErrors(){
      attempted=[];
      pages.forEach(function(page){
        page.classList.remove('mfp-show-errors');
        pageGroups(page).forEach(function(group){group.classList.remove('mfp-field-error-state');});
      });
      setReviewError(false);
    }
    function syncNativePage(el){
      var host=el&&el.closest?el.closest('.mf-page'):null;
      if(!host||host===scope||!scope.contains(host))return;
      var active=!!host.querySelector('[data-mf-native-page].is-active');
      host.hidden=!active;
      host.style.display=active?'block':'none';
      host.setAttribute('aria-hidden',active?'false':'true');
      host.classList.toggle('is-active',active);
      host.classList.toggle('mf-page-active',active);
    }
    function setStep(raw,opts){
      opts=opts||{};
      var idx=parseInt(raw,10);
      if(isNaN(idx))idx=0;
      idx=Math.max(0,Math.min(total-1,idx));
      if(opts.clearErrors)clearErrors();
      scope.setAttribute('data-mf-current-step',String(idx));
      steps.forEach(function(el,i){
        var on=i===idx;
        var done=i<requiredTotal&&computePageValid(i);
        var invalid=i<requiredTotal&&attempted[i]===true&&!done;
        el.classList.toggle('is-active',on);
        el.classList.toggle('is-done',done&&!on);
        el.classList.toggle('is-invalid',invalid);
        el.setAttribute('aria-current',on?'step':'false');
        el.setAttribute('aria-selected',on?'true':'false');
        var check=el.querySelector('.mfp-tab-check');
        if(check)check.textContent='\u2713';
        if(el.tagName==='BUTTON')el.disabled=false;
      });
      pages.forEach(function(el,i){
        var on=i===idx;
        el.classList.toggle('is-active',on);
        el.hidden=!on;
        el.style.display=on?'':'none';
        el.setAttribute('aria-hidden',on?'false':'true');
        syncNativePage(el);
      });
      if(back){button(back,true);back.disabled=idx===0;back.classList.toggle('is-disabled',idx===0);}
      button(next,idx<total-1);
      button(submit,idx===total-1);
      if(progress)progress.textContent=completeCount()+' of '+requiredTotal+' sections complete';
      keepActiveVisible(idx);
      measureScroll();
    }
    function markAttempt(idx){attempted[idx]=true;}
    function firstInvalidPage(){
      for(var i=0;i<requiredTotal;i++)if(!computePageValid(i))return i;
      return -1;
    }
    function showReviewIncomplete(){
      for(var i=0;i<requiredTotal;i++)if(!computePageValid(i))markAttempt(i);
      setStep(total-1);
      setReviewError(true);
    }
    function refreshState(){
      attempted.forEach(function(flag,i){if(flag)validatePage(i,true);});
      setStep(current());
    }
    function ensureScrollButtons(){
      if(!tabbar||tabbar.__mfScrollButtonsReady)return;
      tabbar.__mfScrollButtonsReady=true;
      [['left',-1],['right',1]].forEach(function(pair){
        var btn=document.createElement('button');
        btn.type='button';
        btn.className='mfp-tab-scroll mfp-tab-scroll-'+pair[0];
        btn.setAttribute('aria-label',pair[1]<0?'Scroll tabs left':'Scroll tabs right');
        btn.innerHTML=pair[1]<0?'<svg viewBox="0 0 24 24" aria-hidden="true"><path d="M15 18l-6-6 6-6"/></svg>':'<svg viewBox="0 0 24 24" aria-hidden="true"><path d="M9 18l6-6-6-6"/></svg>';
        btn.addEventListener('click',function(e){
          e.preventDefault();e.stopPropagation();
          if(tabbar.scrollBy)tabbar.scrollBy({left:pair[1]*260,behavior:'smooth'});else tabbar.scrollLeft+=pair[1]*260;
          setTimeout(measureScroll,300);
        });
        tabbar.appendChild(btn);
      });
    }
    function measureScroll(){
      if(!tabbar)return;
      var max=Math.max(0,tabbar.scrollWidth-tabbar.clientWidth);
      var left=tabbar.scrollLeft>4;
      var right=tabbar.scrollLeft<max-4;
      tabbar.classList.toggle('can-left',left);
      tabbar.classList.toggle('can-right',right);
    }
    function keepActiveVisible(idx){
      if(!tabbar)return;
      var active=steps[idx];
      if(active&&active.scrollIntoView){
        try{active.scrollIntoView({behavior:'smooth',inline:'center',block:'nearest'});}catch(e){active.scrollIntoView(false);}
      }
    }
    steps.forEach(function(el,i){
      el.classList.remove('is-invalid');
      el.setAttribute('role','tab');
      el.setAttribute('data-tab-index',String(i));
      el.addEventListener('click',function(e){e.preventDefault();e.stopImmediatePropagation();setStep(i,{clearErrors:true});},true);
    });
    if(next)next.addEventListener('click',function(e){
      e.preventDefault();e.stopImmediatePropagation();
      var idx=current();
      if(!validatePage(idx,true)){markAttempt(idx);setStep(idx);return;}
      setStep(idx+1,{clearErrors:true});
    },true);
    if(back)back.addEventListener('click',function(e){
      e.preventDefault();e.stopImmediatePropagation();
      setStep(current()-1,{clearErrors:true});
    },true);
    if(submit)submit.addEventListener('click',function(e){
      if(!allRequiredComplete()){
        e.preventDefault();e.stopImmediatePropagation();
        showReviewIncomplete();
      }
    },true);
    var form=scope.closest?scope.closest('form'):null;
    if(form&&!form.__mfTabbedSubmitGuardReady){
      form.__mfTabbedSubmitGuardReady=true;
      form.addEventListener('submit',function(e){
        if(!scope.contains(e.submitter||document.activeElement))return;
        if(!allRequiredComplete()){
          e.preventDefault();e.stopImmediatePropagation();
          showReviewIncomplete();
        }
      },true);
    }
    scope.addEventListener('input',function(){setTimeout(refreshState,0);},true);
    scope.addEventListener('change',function(){setTimeout(refreshState,0);},true);
    ensureScrollButtons();
    if(tabbar){tabbar.addEventListener('scroll',measureScroll,{passive:true});}
    window.addEventListener('resize',measureScroll);
    var active=steps.findIndex(function(el){return el.classList.contains('is-active');});
    setStep(active>=0?active:0);
    setTimeout(refreshState,100);
    setTimeout(refreshState,1000);
  }
  function boot(){
    if(root&&root.matches&&root.matches('.mfp-tabbed-account-setup'))init(root);
    toArray(document.querySelectorAll('.mfp-tabbed-account-setup')).forEach(init);
  }
  if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',boot,{once:true});
  boot();setTimeout(boot,100);setTimeout(boot,1000);
})(window.__mfCurrentScriptRoot||document,window.__mfScriptContext||{});

settings.customCss:
body .mfp.mfp-tabbed-account-setup .mf-option-item{display:flex!important;align-items:flex-start;gap:0!important;grid-template-columns:none!important;}
body .mfp.mfp-tabbed-account-setup .mf-option-control{flex:0 0 auto;}
body .mfp.mfp-tabbed-account-setup .mf-option-ui{flex:1 1 auto;min-width:0;}
/* MegaForm Premium Template - Tabbed Account Setup */
.mfp.mfp-tabbed-account-setup,
.mfp.mfp-tabbed-account-setup *,
.mfp.mfp-tabbed-account-setup *::before,
.mfp.mfp-tabbed-account-setup *::after{box-sizing:border-box;}
.mfp.mfp-tabbed-account-setup{--tab-ink:#101828;--tab-sub:#667085;--tab-muted:#98a2b3;--tab-accent:#4338ca;--tab-accent-soft:#eef2ff;--tab-ring:#e4e7ec;--tab-page:#f4f4f7;--tab-field:#f9fafb;--tab-surface:#fff;--tab-ok:#059669;--tab-ok-soft:#ecfdf5;--tab-danger:#dc2626;font-family:Inter,ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;color:var(--tab-ink);background:var(--tab-page);min-height:100vh;width:100%;padding:32px 16px;}
.mfp.mfp-tabbed-account-setup .mfp-frame{width:100%;max-width:1152px;margin:0 auto;}
.mfp.mfp-tabbed-account-setup .mfp-card{overflow:hidden;background:var(--tab-surface);border:1px solid var(--tab-ring);border-radius:24px;box-shadow:0 24px 60px -20px rgba(16,24,40,.28),0 8px 24px -12px rgba(67,56,202,.14);}
.mfp.mfp-tabbed-account-setup .mfp-header{padding:28px 48px 20px;}
.mfp.mfp-tabbed-account-setup .mfp-brand-row{display:flex;align-items:center;gap:8px;}
.mfp.mfp-tabbed-account-setup .mfp-brand-mark{display:grid;place-items:center;width:32px;height:32px;border-radius:8px;background:var(--tab-accent);color:#fff;}
.mfp.mfp-tabbed-account-setup svg{width:1em;height:1em;fill:none;stroke:currentColor;stroke-width:2;stroke-linecap:round;stroke-linejoin:round;}
.mfp.mfp-tabbed-account-setup .mfp-brand-mark svg{width:16px;height:16px;}
.mfp.mfp-tabbed-account-setup .mfp-eyebrow{font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.28em;color:var(--tab-muted);}
.mfp.mfp-tabbed-account-setup .mfp-title{margin:12px 0 0;font-size:27px;line-height:1.22;font-weight:800;color:var(--tab-ink);}
.mfp.mfp-tabbed-account-setup .mfp-subtitle{margin:4px 0 0;max-width:660px;font-size:14px;line-height:1.6;color:var(--tab-sub);}
.mfp.mfp-tabbed-account-setup .mfp-tabbar{position:relative;background:#fcfcfd;border-top:1px solid var(--tab-ring);border-bottom:1px solid var(--tab-ring);overflow-x:auto;-webkit-overflow-scrolling:touch;scrollbar-width:none;}
.mfp.mfp-tabbed-account-setup .mfp-tabbar::-webkit-scrollbar{display:none;}
.mfp.mfp-tabbed-account-setup .mfp-tab-list{display:flex;min-width:max-content;padding:0 40px;}
.mfp.mfp-tabbed-account-setup .mfp-tab{position:relative;appearance:none;border:0;background:transparent;display:flex;align-items:center;gap:10px;min-width:132px;flex:1;padding:14px 12px 15px;text-align:left;color:var(--tab-sub);cursor:pointer;white-space:nowrap;}
.mfp.mfp-tabbed-account-setup .mfp-tab::after{content:'';position:absolute;left:8px;right:8px;bottom:0;height:2px;border-radius:999px;background:transparent;}
.mfp.mfp-tabbed-account-setup .mfp-tab.is-active::after{background:var(--tab-accent);}
.mfp.mfp-tabbed-account-setup .mfp-tab-chip{display:grid;place-items:center;width:32px;height:32px;flex:0 0 32px;border:1px solid var(--tab-ring);border-radius:50%;background:#fff;color:var(--tab-sub);font-size:16px;transition:background .18s,border-color .18s,color .18s;}
.mfp.mfp-tabbed-account-setup .mfp-tab-icon,.mfp.mfp-tabbed-account-setup .mfp-tab-check{grid-area:1/1;display:grid;place-items:center;}
.mfp.mfp-tabbed-account-setup .mfp-tab-icon svg{width:16px;height:16px;}
.mfp.mfp-tabbed-account-setup .mfp-tab-check{display:none;font-size:16px;font-weight:800;line-height:1;}
.mfp.mfp-tabbed-account-setup .mfp-tab.is-active .mfp-tab-chip{background:var(--tab-accent);border-color:var(--tab-accent);color:#fff;}
.mfp.mfp-tabbed-account-setup .mfp-tab.is-done .mfp-tab-chip{background:var(--tab-ok-soft);border-color:var(--tab-ok);color:var(--tab-ok);}
.mfp.mfp-tabbed-account-setup .mfp-tab.is-done .mfp-tab-icon{display:none;}
.mfp.mfp-tabbed-account-setup .mfp-tab.is-done .mfp-tab-check{display:grid;}
.mfp.mfp-tabbed-account-setup .mfp-tab-label{display:block;font-size:13px;line-height:1.15;font-weight:700;color:var(--tab-sub);}
.mfp.mfp-tabbed-account-setup .mfp-tab-hint{display:block;margin-top:2px;font-size:11px;line-height:1.15;color:var(--tab-muted);}
.mfp.mfp-tabbed-account-setup .mfp-tab.is-active .mfp-tab-label{color:var(--tab-ink);}
.mfp.mfp-tabbed-account-setup .mfp-body{padding:28px 48px 36px;background:#fff;}
.mfp.mfp-tabbed-account-setup .mfp-page{display:none!important;}
.mfp.mfp-tabbed-account-setup .mfp-page.is-active{display:block!important;}
.mfp.mfp-tabbed-account-setup .mfp-grid{display:grid;gap:16px;width:100%;}
.mfp.mfp-tabbed-account-setup .mfp-grid-2{grid-template-columns:repeat(2,minmax(0,1fr));}
.mfp.mfp-tabbed-account-setup .mfp-stack{display:flex;flex-direction:column;gap:22px;}
.mfp.mfp-tabbed-account-setup .mfp-field-wrap{min-width:0;}
.mfp.mfp-tabbed-account-setup .mf-field-group{margin:0!important;}
.mfp.mfp-tabbed-account-setup .mf-field-label{display:block;margin:0 0 6px!important;font-size:13px!important;line-height:1.35;font-weight:600!important;color:var(--tab-sub)!important;}
.mfp.mfp-tabbed-account-setup .mf-required{color:var(--tab-accent)!important;}
.mfp.mfp-tabbed-account-setup .mf-input,
.mfp.mfp-tabbed-account-setup .mf-select,
.mfp.mfp-tabbed-account-setup .mf-textarea{width:100%!important;border:1px solid var(--tab-ring)!important;border-radius:12px!important;background:var(--tab-field)!important;color:var(--tab-ink)!important;font:inherit!important;font-size:14px!important;line-height:1.45!important;box-shadow:none!important;outline:none!important;transition:border-color .16s,box-shadow .16s,background .16s;}
.mfp.mfp-tabbed-account-setup .mf-input,
.mfp.mfp-tabbed-account-setup .mf-select{min-height:42px!important;height:42px!important;padding:9px 14px!important;}
.mfp.mfp-tabbed-account-setup .mf-textarea{min-height:92px!important;resize:vertical!important;padding:10px 14px!important;}
.mfp.mfp-tabbed-account-setup .mf-input:focus,
.mfp.mfp-tabbed-account-setup .mf-select:focus,
.mfp.mfp-tabbed-account-setup .mf-textarea:focus{border-color:var(--tab-accent)!important;box-shadow:0 0 0 4px var(--tab-accent-soft)!important;background:#fff!important;}
.mfp.mfp-tabbed-account-setup .mf-input::placeholder,
.mfp.mfp-tabbed-account-setup .mf-textarea::placeholder{color:#9aa3b2!important;}
.mfp.mfp-tabbed-account-setup .mf-field-error{margin-top:6px!important;font-size:12px!important;color:var(--tab-danger)!important;}
.mfp.mfp-tabbed-account-setup .mfp-card-options .mf-option-group--cards{display:grid!important;gap:10px!important;}
.mfp.mfp-tabbed-account-setup .mfp-card-options-2 .mf-option-group--cards{grid-template-columns:repeat(2,minmax(0,1fr))!important;}
.mfp.mfp-tabbed-account-setup .mfp-card-options-3 .mf-option-group--cards{grid-template-columns:repeat(3,minmax(0,1fr))!important;}
.mfp.mfp-tabbed-account-setup .mf-option-item--cards{position:relative;width:100%;min-height:74px;padding:14px!important;border:1.5px solid var(--tab-ring)!important;border-radius:12px!important;background:#fff!important;box-shadow:0 1px 2px rgba(16,24,40,.04);cursor:pointer;transition:border-color .18s,background .18s,box-shadow .18s,transform .12s;}
.mfp.mfp-tabbed-account-setup .mf-option-item--cards:hover{border-color:#c7cce2!important;box-shadow:0 8px 18px -14px rgba(16,24,40,.38);}
.mfp.mfp-tabbed-account-setup .mf-option-item--cards:has(.mf-option-control:checked){border-color:var(--tab-accent)!important;background:#f7f7ff!important;box-shadow:0 6px 18px -8px rgba(67,56,202,.32);}
.mfp.mfp-tabbed-account-setup .mf-option-item--cards .mf-option-control{position:absolute;opacity:0;pointer-events:none;}
.mfp.mfp-tabbed-account-setup .mf-option-item--cards .mf-option-ui{display:flex;align-items:flex-start;gap:12px;width:100%;min-width:0;}
.mfp.mfp-tabbed-account-setup .mf-option-item--cards .mf-option-icon{display:grid;place-items:center;width:40px;height:40px;flex:0 0 40px;border-radius:9px;background:var(--tab-accent-soft);color:var(--tab-accent);font-size:16px;}
.mfp.mfp-tabbed-account-setup .mf-option-item--cards:has(.mf-option-control:checked) .mf-option-icon{background:var(--tab-accent);color:#fff;}
.mfp.mfp-tabbed-account-setup .mf-option-copy{display:flex;flex:1;min-width:0;flex-direction:column;gap:2px;padding-right:24px;}
.mfp.mfp-tabbed-account-setup .mf-option-label{font-size:15px;font-weight:700;color:var(--tab-ink);line-height:1.25;white-space:normal;}
.mfp.mfp-tabbed-account-setup .mf-option-desc{font-size:12px;line-height:1.35;color:var(--tab-sub);white-space:normal;}
.mfp.mfp-tabbed-account-setup .mf-option-meta{font-size:14px;font-weight:800;color:var(--tab-ink);line-height:1.25;}
.mfp.mfp-tabbed-account-setup .mf-option-badge{display:inline-flex;align-items:center;justify-content:center;align-self:flex-start;margin-left:auto;border-radius:999px;background:var(--tab-accent);color:#fff;font-size:10px;font-weight:800;text-transform:uppercase;letter-spacing:.04em;padding:3px 8px;}
.mfp.mfp-tabbed-account-setup .mf-option-check{position:absolute;right:14px;bottom:14px;display:grid!important;place-items:center;width:20px;height:20px;border:2px solid var(--tab-ring);border-radius:50%;color:transparent;font-size:12px;line-height:1;}
.mfp.mfp-tabbed-account-setup .mf-option-control:checked ~ .mf-option-ui .mf-option-check{border-color:var(--tab-accent);background:var(--tab-accent);color:#fff;}
.mfp.mfp-tabbed-account-setup .mfp-chip-options .mf-option-group--chips{display:flex!important;flex-wrap:wrap!important;gap:8px!important;}
.mfp.mfp-tabbed-account-setup .mf-option-item--chips{position:relative;display:inline-flex!important;align-items:center!important;width:auto!important;min-height:36px;padding:0!important;border:0!important;background:transparent!important;cursor:pointer;}
.mfp.mfp-tabbed-account-setup .mf-option-item--chips .mf-option-control{position:absolute;opacity:0;pointer-events:none;}
.mfp.mfp-tabbed-account-setup .mf-option-item--chips .mf-option-ui{display:inline-flex;align-items:center;gap:6px;border:1.5px solid var(--tab-ring);border-radius:999px;background:#fff;color:var(--tab-ink);padding:8px 12px;font-size:14px;font-weight:600;transition:border-color .16s,background .16s,color .16s;}
